FormScriptItem.Script:
// FormValidation for Contact Us form

//pass in ControlName to validate a single item or nothing to validate everything.
var ErrorReporting = true;

var RunAll = false;
if (ControlName == null) {
  RunAll = true;

  //DOB - Date must be before today.
  if (ControlName == 'DOB' || RunAll) {
    if (
      VV.Form.Global.CentralDateValidation(
        VV.Form.GetFieldValue('DOB'),
        'BeforeToday'
      ) == false
    ) {
      VV.Form.SetValidationErrorMessageOnField(
        'DOB',
        'The date must be before today.'
      );
      ErrorReporting = false;
    } else {
      VV.Form.ClearValidationErrorOnField('DOB');
    }
  }

  //Email - Email Address is required and must be entered as a valid email address format.
  if (ControlName == 'Email' || RunAll) {
    if (
      VV.Form.Global.CentralValidation(
        VV.Form.GetFieldValue('Email'),
        'Email'
      ) == false
    ) {
      VV.Form.SetValidationErrorMessageOnField(
        'Email',
        'Please enter the Email in the form of a valid Email Address.'
      );
      ErrorReporting = false;
    } else {
      VV.Form.ClearValidationErrorOnField('Email');
    }
  }

  //Name - Textbox that must not be blank or equal to 'Enter your name'.
  if (ControlName == 'Name' || RunAll) {
    if (
      VV.Form.Global.CentralValidation(
        VV.Form.GetFieldValue('Name'),
        'Blank'
      ) == false ||
      VV.Form.GetFieldValue('Name') == 'Enter your name'
    ) {
      VV.Form.SetValidationErrorMessageOnField(
        'Name',
        'A value needs to be entered in the Name field.'
      );
      ErrorReporting = false;
    } else {
      VV.Form.ClearValidationErrorOnField('Enter text in the Name field.');
    }
  }
}

//Text Box that must be filled out
if (ControlName == 'Message' || RunAll) {
  if (
    VV.Form.Global.CentralValidation(
      VV.Form.GetFieldValue('Message'),
      'Blank'
    ) == false
  ) {
    VV.Form.SetValidationErrorMessageOnField(
      'Message',
      'A value needs to be entered.'
    );
    ErrorReporting = false;
  } else {
    VV.Form.ClearValidationErrorOnField('Enter text in the Message field.');
  }
}

//Phone - Phone Number is required and must be in a phone number format when entered.
if (ControlName == 'Phone' || RunAll) {
  if (
    VV.Form.Global.CentralValidation(VV.Form.GetFieldValue('Phone'), 'Phone') ==
    false
  ) {
    VV.Form.SetValidationErrorMessageOnField(
      'Phone',
      'A phone number must be entered in the format of (XXX) XXX-XXXX.'
    );
    ErrorReporting = false;
  } else {
    VV.Form.ClearValidationErrorOnField('Phone');
  }
}

return ErrorReporting;

//Update Status field to 'Pending' and save the form
VV.Form.SetFieldValue('Status', 'Pending', false);
VV.Form.DoAjaxFormSave().then(() => {
       VV.Form.HideLoadingPanel();
  });

if(VV.Form.GetFieldValue('Name')==''){
   VV.Form.SetFieldValue('Name', 'Enter your name', false)
}

VV.Form.Template.FormValidation('Name');

if (buttonText === 'btn1') {
    VV.Form.SetFieldValue('Status', 'Escalated', false);
  }
if (buttonText === 'btn2') {
    VV.Form.SetFieldValue('Status', 'Reviewed', false);
  }

Promise.all([
   VV.Form.SetFieldValue('Name', 'Enter your name', false),
   VV.Form.SetFieldValue('Email', '', false),
   VV.Form.SetFieldValue('Phone', '', false),
   VV.Form.SetFieldValue('DOB', '', false),
   VV.Form.SetFieldValue('Message', '', false)
]).then(function () {
   VV.Form.DoAjaxFormSave();
});

var message = 'Select OK to confirm this action and submit the form.';

var okfunction = function () {
    VV.Form.Template.Submit();
}

var cancelfunction = function () {
    return;
}

VV.Form.Global.DisplayConfirmMessaging(message, 'Confirm', okfunction, 
cancelfunction);
